INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00277', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["對於受刑人，應施以教化，並應參酌受刑人之入監調查結果及個別處遇計畫，施以適當之輔導與教育", "受刑人得自備書籍、報紙、點字讀物或請求使用紙筆及其他必要之用品，書籍之內容與類型，不得 限制或禁止之", "監獄得安排專人或轉介機關（構）、法人、團體協助受刑人與被害人進行調解及修復事宜", "受刑人有信仰宗教之自由，不得限制或禁止之。但宗教活動有妨害監獄秩序或安全者，不在此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00278', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '行刑累進處遇條例對於受刑人接見及發受書信有特別規定時，應優先於監獄行刑法適用，以下關於接 見及發受書信之規定，下列何者正確？', '["第四級受刑人，得准其與非親屬接見及發受書信", "第二級受刑人接見及寄發書信之次數不予限制", "第二級以上之受刑人，於接見時，得不加監視", "第一級受刑人，應於接見所接見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00279', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，有關監獄作業制度的敘述，下列何者正確？', '["作業時間應斟酌教化、數量、作業之種類、設備之狀況及其他情形定之，每日不得逾八小時。但有 特殊情形，得將作業時間延長之，延長之作業時間連同正常作業時間，一日不得超過十小時，避免 受刑人過勞", "受刑人之作業以勞動能率或作業時間作為課程；其勞動能率應依受刑人個人之工作產能酌定，以符 個別化原則", "監獄作業方式，以自營、委託加工、承攬、指定監外作業或其他作業為之", "受刑人之配偶、直系親屬或三親等內旁系親屬喪亡者，得停止受刑人之作業，但停止作業期間最長 以二週為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00280', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄認受刑人或請求接見者有相當理由時，得准其使用電話或其他通訊方式接見，有關使用通訊設備 接見之方式，下列敘述何者錯誤？', '["律師或辯護人，未便至機關接見為使用電話或其他通訊方式接見的相當理由之一", "收容人使用通訊設備接見，原則上每次以30分鐘為限", "收容人使用通訊設備接見，原則上得每月3次", "所謂通訊設備，不僅以電話為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00281', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為鼓勵受刑人保持善行，有關監獄獎勵受刑人之限制，下列敘述何者錯誤？', '["採法規保留原則", "原則上禁止重複獎勵", "不得以不正當手段獲取獎勵", "給予特別獎勵，監獄得報請監督機關備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00282', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '為維護監獄行刑秩序及紀律，有關監獄懲罰受刑人之限制，下列敘述何者錯誤？', '["採法律保留原則", "同一事件得重複懲罰", "嚴禁體罰", "不得有礙身心健康，也不得有差別待遇"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00283', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，有關監獄作業制度的敘述，下列何者正確？', '["為落實復歸社會目的，並維人性尊嚴，受刑人有選擇作業與否以及內容的自由", "監獄對作業應斟酌衛生、教化、經濟效益與受刑人之刑期、健康、知識、技能及出獄後之生計定之， 並按作業性質，使受刑人在監內、外工場或其他特定場所為之", "受刑人從事炊事、打掃、營繕、看護及其他由監獄指定之事務，不視同作業", "受刑人在監外作業，應於指定時間內回監，必要時得向指定處所報到。其無正當理由未於指定時間 內回監或向指定處所報到者，在外期間不算入執行刑期，但不得以脫逃罪論處"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00284', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者錯誤？', '["為維護受刑人之身體健康，監獄應供給飲食，並提供必要之衣類、寢具、物品及其他器具", "攜帶入監或在監生產之受刑人子女，其食物、衣類及必需用品，均由監獄提供之", "監獄得許受刑人於指定之時間、處所吸菸，並應對受刑人施以菸害防制教育、宣導，對戒菸之受刑 人給予適當之獎勵", "監獄除國定例假日、休息日或有特殊事由外，應給予受刑人每日運動一小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00285', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依據監獄行刑法以及相關法規之規定，下列敘述何者正確？', '["接見，每次不得逾五人。但本法或其他法規另有規定，或經監獄長官許可者，不在此限", "被許可接見者，得攜帶未滿十五歲之兒童，不計入人數限制之範圍", "監獄基於管理、教化輔導、受刑人個人重大事故或其他事由，認為必要時，監獄長官得准受刑人於 監獄內指定處所辦理接見", "監獄對受刑人之接見，不得予以監看，亦不得以錄影、錄音方式記錄之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00286', 'judicial-57112235', 'judicial-57112235-moex-113-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '收容人某甲，於A監獄接受有期徒刑之執行期間，因病猝死。依據監獄行刑法以及相關規定，下列敘 述何者錯誤？', '["受刑人甲於執行中死亡，監獄應即通知甲之家屬或最近親屬，家屬或最近親屬有數人者，得僅通知 其中一人", "受刑人甲於執行中死亡，監獄應逕報檢察署指派檢察官相驗", "受刑人甲於執行中死亡，縱使監獄知悉甲生前有委任律師，且其委任事務尚未處理完畢，亦無須通 知甲之律師", "受刑人甲於執行中死亡，監獄應檢附相關資料，陳報監督機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:50+00:00", "source_pdf_sha1": "985208735e01", "answer_pdf_sha1": "06835924ef33", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
